// HTML yang dibutuhkan: tambahkan di atas tabel
// <input type="search" id="searchInput" placeholder="Cari artikel...">

const searchInput = document.getElementById('searchInput');

// Event: jalankan setiap karakter yang diketik
searchInput.addEventListener('input', function() {
  const keyword = this.value.trim().toLowerCase();
  searchArticles(keyword);
});

function searchArticles(keyword) {
  if (!keyword) {
    renderTable(articles); // Kosong = tampilkan semua
    return;
  }

  const results = articles.filter(a =>
    a.title.toLowerCase().includes(keyword) ||
    a.content.toLowerCase().includes(keyword)
  );

  renderTable(results); // renderTable sudah menerima parameter data

  // Feedback jumlah hasil
  if (results.length === 0) {
    tableBody.innerHTML = `
      <tr><td colspan="5" class="empty-state">
        Tidak ada artikel yang cocok dengan "${keyword}".
      </td></tr>
    `;
  }
}

// ⚠️ Pastikan renderTable() menerima parameter:
// function renderTable(data = articles) { ... }
//                      ↑ Default ke articles jika tidak ada argumen

